import ts from"typescript";import{stripQuotes}from"../../../typescript/ast-helpers.js";import{hasImportSpecifier}from"../../../typescript/visitors/helpers.js";import{scriptVisitor as visit}from"../../../typescript/visitors/index.js";const tags=new Set(["$","$sync"]),methods=new Set(["execa","execaSync","execaCommand","execaCommandSync","$sync"]);export default visit(t=>t.statements.some(t=>hasImportSpecifier(t,"execa")),t=>{if(ts.isTaggedTemplateExpression(t)&&(tags.has(t.tag.getText())||ts.isCallExpression(t.tag)&&tags.has(t.tag.expression.getText())))return stripQuotes(t.template.getText());if(ts.isCallExpression(t)){const e=t.expression.getText();if(methods.has(e))if(e.startsWith("execaCommand")){if(t.arguments[0]&&ts.isStringLiteral(t.arguments[0]))return stripQuotes(t.arguments[0].getText())}else{const[e,s]=t.arguments;if(e&&ts.isStringLiteral(e)){const t=stripQuotes(e.getText());if(s&&ts.isArrayLiteralExpression(s)){return[t,...s.elements.filter(ts.isStringLiteral).map(t=>stripQuotes(t.getText()))].join(" ")}return t}}}});